use crate::protocol::{address::AztecAddress, traits::{Deserialize, Serialize}};

/// Stores arbitrary information in a per-contract non-volatile database, which can later be retrieved with `load`. If
/// data was already stored at this slot, it is overwritten.
// TODO(F-498): review naming consistency
pub unconstrained fn store<T>(contract_address: AztecAddress, slot: Field, value: T, scope: AztecAddress)
where
    T: Serialize,
{
    let serialized = value.serialize();
    set_capsule_oracle(contract_address, slot, serialized, scope);
}

/// Returns data previously stored via `storeCapsule` in the per-contract non-volatile database. Returns
/// Option::none() if nothing was stored at the given slot.
// TODO(F-498): review naming consistency
pub unconstrained fn load<T>(contract_address: AztecAddress, slot: Field, scope: AztecAddress) -> Option<T>
where
    T: Deserialize,
{
    let serialized_option = get_capsule_oracle(contract_address, slot, <T as Deserialize>::N, scope);
    serialized_option.map(|arr| Deserialize::deserialize(arr))
}

/// Deletes data in the per-contract non-volatile database. Does nothing if no data was present.
pub unconstrained fn delete(contract_address: AztecAddress, slot: Field, scope: AztecAddress) {
    delete_oracle(contract_address, slot, scope);
}

/// Copies a number of contiguous entries in the per-contract non-volatile database. This allows for efficient data
/// structures by avoiding repeated calls to `loadCapsule` and `storeCapsule`. Supports overlapping source and
/// destination regions (which will result in the overlapped source values being overwritten). All copied slots must
/// exist in the database (i.e. have been stored and not deleted)
pub unconstrained fn copy(
    contract_address: AztecAddress,
    src_slot: Field,
    dst_slot: Field,
    num_entries: u32,
    scope: AztecAddress,
) {
    copy_oracle(contract_address, src_slot, dst_slot, num_entries, scope);
}

#[oracle(aztec_utl_setCapsule)]
unconstrained fn set_capsule_oracle<let N: u32>(
    contract_address: AztecAddress,
    slot: Field,
    values: [Field; N],
    scope: AztecAddress,
) {}

/// We need to pass in `array_len` (the value of N) as a parameter to tell the oracle how many fields the response must
/// have.
///
/// Note that the oracle returns an Option<[Field; N]> because we cannot return an Option<T> directly. That would
/// require for the oracle resolver to know the shape of T (e.g. if T were a struct of 3 u32 values then the expected
/// response shape would be 3 single items, whereas it were a struct containing `u32, [Field;10], u32` then the
/// expected shape would be single, array, single.). Instead, we return the serialization and deserialize in Noir.
#[oracle(aztec_utl_getCapsule)]
unconstrained fn get_capsule_oracle<let N: u32>(
    contract_address: AztecAddress,
    slot: Field,
    array_len: u32,
    scope: AztecAddress,
) -> Option<[Field; N]> {}

#[oracle(aztec_utl_deleteCapsule)]
unconstrained fn delete_oracle(contract_address: AztecAddress, slot: Field, scope: AztecAddress) {}

#[oracle(aztec_utl_copyCapsule)]
unconstrained fn copy_oracle(
    contract_address: AztecAddress,
    src_slot: Field,
    dst_slot: Field,
    num_entries: u32,
    scope: AztecAddress,
) {}

mod test {
    // These tests are sort of redundant since we already test the oracle implementation directly in TypeScript, but
    // they are cheap regardless and help ensure both that the TXE implementation works accordingly and that the Noir
    // oracles are hooked up correctly.

    use crate::{
        oracle::capsules::{copy, delete, load, store},
        test::{helpers::test_environment::TestEnvironment, mocks::MockStruct},
    };
    use crate::protocol::{address::AztecAddress, traits::{FromField, ToField}};

    global SLOT: Field = 1;
    global SCOPE: AztecAddress = AztecAddress { inner: 0xcafe };

    #[test]
    unconstrained fn stores_and_loads() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let value = MockStruct::new(5, 6);
            store(contract_address, SLOT, value, SCOPE);

            assert_eq(load(contract_address, SLOT, SCOPE).unwrap(), value);
        });
    }

    #[test]
    unconstrained fn store_overwrites() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let value = MockStruct::new(5, 6);
            store(contract_address, SLOT, value, SCOPE);

            let new_value = MockStruct::new(7, 8);
            store(contract_address, SLOT, new_value, SCOPE);

            assert_eq(load(contract_address, SLOT, SCOPE).unwrap(), new_value);
        });
    }

    #[test]
    unconstrained fn loads_empty_slot() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let loaded_value: Option<MockStruct> = load(contract_address, SLOT, SCOPE);
            assert_eq(loaded_value, Option::none());
        });
    }

    #[test]
    unconstrained fn deletes_stored_value() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let value = MockStruct::new(5, 6);
            store(contract_address, SLOT, value, SCOPE);
            delete(contract_address, SLOT, SCOPE);

            let loaded_value: Option<MockStruct> = load(contract_address, SLOT, SCOPE);
            assert_eq(loaded_value, Option::none());
        });
    }

    #[test]
    unconstrained fn deletes_empty_slot() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            delete(contract_address, SLOT, SCOPE);
            let loaded_value: Option<MockStruct> = load(contract_address, SLOT, SCOPE);
            assert_eq(loaded_value, Option::none());
        });
    }

    #[test]
    unconstrained fn copies_non_overlapping_values() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let src = 5;

            let values = [MockStruct::new(5, 6), MockStruct::new(7, 8), MockStruct::new(9, 10)];
            store(contract_address, src, values[0], SCOPE);
            store(contract_address, src + 1, values[1], SCOPE);
            store(contract_address, src + 2, values[2], SCOPE);

            let dst = 10;
            copy(contract_address, src, dst, 3, SCOPE);

            assert_eq(load(contract_address, dst, SCOPE).unwrap(), values[0]);
            assert_eq(load(contract_address, dst + 1, SCOPE).unwrap(), values[1]);
            assert_eq(load(contract_address, dst + 2, SCOPE).unwrap(), values[2]);
        });
    }

    #[test]
    unconstrained fn copies_overlapping_values_with_src_ahead() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let src = 1;

            let values = [MockStruct::new(5, 6), MockStruct::new(7, 8), MockStruct::new(9, 10)];
            store(contract_address, src, values[0], SCOPE);
            store(contract_address, src + 1, values[1], SCOPE);
            store(contract_address, src + 2, values[2], SCOPE);

            let dst = 2;
            copy(contract_address, src, dst, 3, SCOPE);

            assert_eq(load(contract_address, dst, SCOPE).unwrap(), values[0]);
            assert_eq(load(contract_address, dst + 1, SCOPE).unwrap(), values[1]);
            assert_eq(load(contract_address, dst + 2, SCOPE).unwrap(), values[2]);

            // src[1] and src[2] should have been overwritten since they are also dst[0] and dst[1]
            assert_eq(load(contract_address, src, SCOPE).unwrap(), values[0]); // src[0] (unchanged)
            assert_eq(load(contract_address, src + 1, SCOPE).unwrap(), values[0]); // dst[0]
            assert_eq(load(contract_address, src + 2, SCOPE).unwrap(), values[1]); // dst[1]
        });
    }

    #[test]
    unconstrained fn copies_overlapping_values_with_dst_ahead() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            let src = 2;

            let values = [MockStruct::new(5, 6), MockStruct::new(7, 8), MockStruct::new(9, 10)];
            store(contract_address, src, values[0], SCOPE);
            store(contract_address, src + 1, values[1], SCOPE);
            store(contract_address, src + 2, values[2], SCOPE);

            let dst = 1;
            copy(contract_address, src, dst, 3, SCOPE);

            assert_eq(load(contract_address, dst, SCOPE).unwrap(), values[0]);
            assert_eq(load(contract_address, dst + 1, SCOPE).unwrap(), values[1]);
            assert_eq(load(contract_address, dst + 2, SCOPE).unwrap(), values[2]);

            // src[0] and src[1] should have been overwritten since they are also dst[1] and dst[2]
            assert_eq(load(contract_address, src, SCOPE).unwrap(), values[1]); // dst[1]
            assert_eq(load(contract_address, src + 1, SCOPE).unwrap(), values[2]); // dst[2]
            assert_eq(load(contract_address, src + 2, SCOPE).unwrap(), values[2]); // src[2] (unchanged)
        });
    }

    #[test(should_fail_with = "copy empty slot")]
    unconstrained fn cannot_copy_empty_values() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();

            copy(contract_address, SLOT, SLOT, 1, SCOPE);
        });
    }

    #[test(should_fail_with = "not allowed to access")]
    unconstrained fn cannot_store_other_contract() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();
            let other_contract_address = AztecAddress::from_field(contract_address.to_field() + 1);

            let value = MockStruct::new(5, 6);
            store(other_contract_address, SLOT, value, SCOPE);
        });
    }

    #[test(should_fail_with = "not allowed to access")]
    unconstrained fn cannot_load_other_contract() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();
            let other_contract_address = AztecAddress::from_field(contract_address.to_field() + 1);

            let _: Option<MockStruct> = load(other_contract_address, SLOT, SCOPE);
        });
    }

    #[test(should_fail_with = "not allowed to access")]
    unconstrained fn cannot_delete_other_contract() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();
            let other_contract_address = AztecAddress::from_field(contract_address.to_field() + 1);

            delete(other_contract_address, SLOT, SCOPE);
        });
    }

    #[test(should_fail_with = "not allowed to access")]
    unconstrained fn cannot_copy_other_contract() {
        let env = TestEnvironment::new();
        env.private_context(|context| {
            let contract_address = context.this_address();
            let other_contract_address = AztecAddress::from_field(contract_address.to_field() + 1);

            copy(other_contract_address, SLOT, SLOT, 0, SCOPE);
        });
    }
}

